class.description:
[SQLite] 提供面向脚本的 SQLite 数据库连接、SQL 查询、参数绑定、表结构辅助创建、JSON 导入导出和数据库备份接口。每个 [SQLite] 实例持有一个数据库连接；同一个数据库文件可以由多个实例同时打开，但并发写入仍遵循 SQLite 自身的锁和事务规则。
推荐使用 [method open]、[method close]、[method execute]、[method fetch_all] 和 [method fetch_one] 这组更直接的接口完成常见读写；[method open_db]、[method close_db]、[method query]、[method query_with_bindings] 和 [method query_with_named_bindings] 仍保留用于兼容旧代码或需要显式区分绑定方式的场景。
默认情况下，[member path] 会被转换为全局文件路径并以读写模式打开。设置 [member read_only] 后会使用 Godot 文件访问 API 读取数据库，可用于读取打包在 PCK 内的数据库，但只读模式不支持内存数据库。向 SQL 传入用户数据时应优先使用 [method execute]、[method fetch_all] 或 [method fetch_one] 的参数绑定，避免手动拼接值导致 SQL 注入或 BLOB 数据写入失败。
在 C# 中，方法名和属性名会按 Godot 绑定规则转换为 PascalCase，例如 [method open] 对应 [code]Open[/code]，[method fetch_all] 对应 [code]FetchAll[/code]。
[b]示例：打开数据库、建表、写入并查询[/b]
[codeblocks]
[gdscript]
func save_player_score(player_name: String, score: int) -> void:
	var db = SQLite.new()
	if not db.open("user://scores"):
		push_error(db.get_last_error())
		return

	db.execute("""
		CREATE TABLE IF NOT EXISTS scores (
			id INTEGER PRIMARY KEY AUTOINCREMENT,
			name TEXT NOT NULL,
			score INTEGER NOT NULL,
			created_at TEXT DEFAULT CURRENT_TIMESTAMP
		);
	""")
	db.execute("INSERT INTO scores (name, score) VALUES (?, ?);", [player_name, score])

	var rows = db.fetch_all(
			"SELECT name, score FROM scores WHERE score >= :min_score ORDER BY score DESC LIMIT 10;",
			{ "min_score": 100 }
	)
	for row in rows:
		print("%s: %d" % [row["name"], row["score"]])

	db.close()
[/gdscript]
[csharp]
public void SavePlayerScore(string playerName, long score)
{
	var db = new SQLite();
	if (!db.Open("user://scores"))
	{
		GD.PushError(db.GetLastError());
		return;
	}

	db.Execute("CREATE TABLE IF NOT EXISTS scores (" +
			"id INTEGER PRIMARY KEY AUTOINCREMENT, " +
			"name TEXT NOT NULL, " +
			"score INTEGER NOT NULL, " +
			"created_at TEXT DEFAULT CURRENT_TIMESTAMP);");
	db.Execute(
			"INSERT INTO scores (name, score) VALUES (?, ?);",
			new Godot.Collections.Array { playerName, score });

	var rows = db.FetchAll(
			"SELECT name, score FROM scores WHERE score >= :min_score ORDER BY score DESC LIMIT 10;",
			new Godot.Collections.Dictionary { { "min_score", 100 } });
	foreach (Godot.Collections.Dictionary row in rows)
	{
		GD.Print($"{row["name"]}: {row["score"]}");
	}

	db.Close();
}
[/csharp]
[/codeblocks]
[b]示例：读取打包数据库并备份用户数据库[/b]
[codeblocks]
[gdscript]
func load_catalog_title(item_id: int) -> String:
	var catalog = SQLite.new()
	if not catalog.open_read_only("res://data/catalog.db"):
		push_error(catalog.get_last_error())
		return ""

	var row = catalog.fetch_one("SELECT title FROM items WHERE id = ?;", [item_id])
	catalog.close()
	return row.get("title", "")

func backup_save_data() -> void:
	var save_db = SQLite.new()
	if save_db.open("user://save"):
		save_db.backup_to("user://save_backup.db")
		save_db.export_to_json("user://save_export.json")
		save_db.close()
[/gdscript]
[csharp]
public string LoadCatalogTitle(long itemId)
{
	var catalog = new SQLite();
	if (!catalog.OpenReadOnly("res://data/catalog.db"))
	{
		GD.PushError(catalog.GetLastError());
		return "";
	}

	var row = catalog.FetchOne(
			"SELECT title FROM items WHERE id = ?;",
			new Godot.Collections.Array { itemId });
	catalog.Close();
	return row.ContainsKey("title") ? row["title"].ToString() : "";
}

public void BackupSaveData()
{
	var saveDb = new SQLite();
	if (saveDb.Open("user://save"))
	{
		saveDb.BackupTo("user://save_backup.db");
		saveDb.ExportToJson("user://save_export.json");
		saveDb.Close();
	}
}
[/csharp]
[/codeblocks]

method.description:
根据 [param table_data] 创建表。[param table_data] 的每个键是列名，每个值是列定义字典。列定义必须包含 [code]data_type[/code]，支持 [code]int[/code]、[code]real[/code]、[code]text[/code]、[code]char(n)[/code] 和 [code]blob[/code]；可选键包括 [code]not_null[/code]、[code]unique[/code]、[code]default[/code]、[code]primary_key[/code]、[code]auto_increment[/code] 和 [code]foreign_key[/code]。返回 [code]false[/code] 表示表定义无效或 SQL 执行失败。
[b]示例：使用字典描述表结构[/b]
[codeblocks]
[gdscript]
db.create_table("players", {
	"id": {
		"data_type": "int",
		"primary_key": true,
		"auto_increment": true,
	},
	"name": {
		"data_type": "text",
		"not_null": true,
	},
	"score": {
		"data_type": "int",
		"default": 0,
	},
})
[/gdscript]
[csharp]
var table = new Godot.Collections.Dictionary {
	{ "id", new Godot.Collections.Dictionary {
		{ "data_type", "int" },
		{ "primary_key", true },
		{ "auto_increment", true },
	} },
	{ "name", new Godot.Collections.Dictionary {
		{ "data_type", "text" },
		{ "not_null", true },
	} },
	{ "score", new Godot.Collections.Dictionary {
		{ "data_type", "int" },
		{ "default", 0 },
	} },
};
db.CreateTable("players", table);
[/csharp]
[/codeblocks]
